 190→type ReminderSubView = 'list' | 'create' | 'edit';
 191→
 192→interface ReminderFormState {
 193→  title: string;
 194→  dueDate: string;
 195→  dueTime: string;
 196→  repeat: RepeatOption;
 197→  notes: string;
 198→}
 199→
 200→const INITIAL_FORM: ReminderFormState = {
 201→  title: '',
 202→  dueDate: new Date().toISOString().slice(0, 10),
 203→  dueTime: '09:00',
 204→  repeat: 'none',
 205→  notes: '',
 206→};
 207→
 208→interface EditReminderViewProps {
 209→  reminder?: ReminderEntry;
 210→  onSubmit: (form: ReminderFormState) => void;
 211→}
 212→
 213→function EditReminderView({ reminder, onSubmit }: EditReminderViewProps) {
 214→  const [form, setForm] = useState<ReminderFormState>(() => {
 215→    if (reminder) {
 216→      return {
 217→        title: reminder.title,
 218→        dueDate: reminder.dueDate.toISOString().slice(0, 10),
 219→        dueTime: reminder.dueTime,
 220→        repeat: reminder.repeat,
 221→        notes: reminder.notes,
 222→      };
 223→    }
 224→    return INITIAL_FORM;
 225→  });
 226→
 227→  const [errors, setErrors] = useState<
 228→    Partial<Record<keyof ReminderFormState, string>>
 229→  >({});
 230→
 231→  const handleSubmit = useCallback(() => {
 232→    const newErrors: Partial<Record<keyof ReminderFormState, string>> = {};
 233→
 234→    if (!form.title.trim()) {
 235→      newErrors.title = 'Title is required';
 236→    }
 237→    if (!form.dueDate) {
 238→      newErrors.dueDate = 'Due date is required';
 239→    }
 240→
 241→    setErrors(newErrors);
 242→    if (Object.keys(newErrors).length > 0) return;
 243→
 244→    onSubmit(form);
 245→  }, [
 246→    form,
 247→    onSubmit,
 248→  ]);
 249→
 250→  return (
 251→    <div className="reminder-form">
 252→      <Form onSubmit={handleSubmit}>
 253→        <FormTextField
 254→          label="Title"
 255→          value={form.title}
 256→          onChange={v =>
 257→            setForm(prev => ({
 258→              ...prev,
 259→              title: v,
 260→            }))
 261→          }
 262→          placeholder="e.g. Call dentist"
 263→          error={errors.title}
 264→          autoFocus
 265→        />
 266→        <FormDatePicker
 267→          label="Due Date"
 268→          value={form.dueDate}
 269→          onChange={v =>
 270→            setForm(prev => ({
 271→              ...prev,
 272→              dueDate: v,
 273→            }))
 274→          }
 275→          error={errors.dueDate}
 276→        />
 277→        <FormTextField
 278→          label="Time"
 279→          value={form.dueTime}
 280→          onChange={v =>
 281→            setForm(prev => ({
 282→              ...prev,
 283→              dueTime: v,
 284→            }))
 285→          }
 286→          placeholder="HH:MM"
 287→        />
 288→        <FormDropdown
 289→          label="Repeat"
 290→          value={form.repeat}
 291→          onChange={v => {
 292→            if (isRepeatOption(v)) {
 293→              setForm(prev => ({
 294→                ...prev,
 295→                repeat: v,
 296→              }));
 297→            }
 298→          }}
 299→          options={REPEAT_OPTIONS}
 300→        />
 301→        <FormTextArea
 302→          label="Notes"
 303→          value={form.notes}
 304→          onChange={v =>
 305→            setForm(prev => ({
 306→              ...prev,
 307→              notes: v,
 308→            }))
 309→          }
 310→          placeholder="Additional details..."
 311→          rows={4}
 312→        />
 313→      </Form>
 314→    </div>
 315→  );
 316→}
