 71→type DatabaseInstance = {
 72→  execute(
 73→    query: string,
 74→    bindValues?: unknown[],
 75→  ): Promise<{ rowsAffected: number }>;
 76→  select<T>(query: string, bindValues?: unknown[]): Promise<T>;
