 79→let dbInstance: DatabaseInstance | undefined;
 80→let dbPromise: Promise<DatabaseInstance> | undefined;
 81→
 82→async function loadDb(): Promise<DatabaseInstance> {
 83→  const Database = (await import('@tauri-apps/plugin-sql')).default;
 84→  return Database.load(DB_PATH);
 85→}
 86→
 87→function getDb(): Promise<DatabaseInstance> {
 88→  if (dbInstance) return Promise.resolve(dbInstance);
 89→  if (dbPromise) return dbPromise;
 90→
 91→  dbPromise = loadDb()
 92→    .then(db => {
 93→      dbInstance = db;
 94→      return db;
 95→    })
 96→    .catch(err => {
 97→      dbPromise = undefined;
 98→      throw err;
 99→    });
100→
101→  return dbPromise;
102→}
