147→function buildUpdateQuery(
148→  table: string,
149→  updates: Record<string, unknown>,
150→  allowedColumns: Set<string>,
151→  id: string
152→): {
153→  sql: string;
154→  values: unknown[];
155→} | null {
156→  const fields: string[] = [];
157→  const values: unknown[] = [];
158→  let idx = 1;
159→
160→  for (const [key, value] of Object.entries(updates)) {
161→    if (!allowedColumns.has(key)) continue;
162→    fields.push(`${key} = $${idx}`);
163→    values.push(value);
164→    idx++;
165→  }
166→
167→  if (fields.length === 0) return null;
168→  values.push(id);
169→  return {
170→    sql: `UPDATE ${table} SET ${fields.join(', ')} WHERE id = $${idx}`,
171→    values,
172→  };
173→}
