175→function escapeLikeQuery(query: string): string {
176→  return query.replace(/[\\%_]/g, ch => `\\${ch}`);
177→}
178→
179→function escapeFts5Query(query: string): string {
180→  return query
181→    .split(/\s+/)
182→    .filter(Boolean)
183→    .map(token => `"${token.replace(/"/g, '""')}"`)
184→    .join(' ');
185→}
