269→export const clipboardDb = {
270→  async getAll(limit = 1000): Promise<ClipboardEntryRow[]> {
271→    if (isTauri) {
272→      const db = await getDb();
273→      return db.select<ClipboardEntryRow[]>(
274→        'SELECT id, content, content_type, source_app, copied_at, pinned FROM clipboard_entries ORDER BY pinned DESC, copied_at DESC LIMIT $1',
275→        [limit],
276→      );
277→    }
278→    return storageGet('clipboard-history', isClipboardRowArray) ?? [];
279→  },
280→  async insert(entry: ClipboardEntryRow): Promise<void> {
281→    if (isTauri) {
282→      const db = await getDb();
283→      await db.execute(
284→        'INSERT INTO clipboard_entries (id, content, content_type, source_app, copied_at, pinned) VALUES ($1, $2, $3, $4, $5, $6)',
285→        [
286→          entry.id,
287→          entry.content,
288→          entry.content_type,
289→          entry.source_app,
290→          entry.copied_at,
291→          entry.pinned,
292→        ],
293→      );
294→      return;
295→    }
296→    const all = await this.getAll();
297→    all.unshift(entry);
298→    storageSet('clipboard-history', all);
299→  },
300→  async update(
301→    id: string,
302→    updates: Partial<Omit<ClipboardEntryRow, 'id'>>,
303→  ): Promise<void> {
304→    if (isTauri) {
305→      const db = await getDb();
306→      const query = buildUpdateQuery(
307→        'clipboard_entries',
308→        updates,
309→        CLIPBOARD_COLUMNS,
310→        id,
311→      );
312→      if (!query) return;
313→      await db.execute(query.sql, query.values);
314→      return;
315→    }
316→    const all = await this.getAll();
317→    const updated = all.map(r =>
318→      r.id === id
319→        ? {
320→            ...r,
321→            ...updates,
322→          }
323→        : r);
324→    storageSet('clipboard-history', updated);
325→  },
326→  async delete(id: string): Promise<void> {
327→    if (isTauri) {
328→      const db = await getDb();
329→      await db.execute('DELETE FROM clipboard_entries WHERE id = $1', [id]);
330→      return;
331→    }
332→    const all = await this.getAll();
333→    storageSet(
334→      'clipboard-history',
335→      all.filter(r => r.id !== id),
336→    );
337→  },
338→  async clear(): Promise<void> {
339→    if (isTauri) {
340→      const db = await getDb();
341→      await db.execute('DELETE FROM clipboard_entries');
342→      return;
343→    }
344→    storageRemove('clipboard-history');
345→  },
346→  async search(query: string, limit = 50): Promise<ClipboardEntryRow[]> {
347→    if (isTauri) {
348→      const escaped = escapeFts5Query(query);
349→      if (!escaped) return [];
350→      const db = await getDb();
351→      return db.select<ClipboardEntryRow[]>(
352→        `SELECT ce.id, ce.content, ce.content_type, ce.source_app, ce.copied_at, ce.pinned
353→         FROM clipboard_entries ce
354→         JOIN clipboard_entries_fts fts ON ce.rowid = fts.rowid
355→         WHERE clipboard_entries_fts MATCH $1
356→         ORDER BY ce.pinned DESC, ce.copied_at DESC
357→         LIMIT $2`,
358→        [
359→          escaped,
360→          limit,
361→        ],
362→      );
363→    }
364→    const all = await this.getAll();
365→    const q = query.toLowerCase();
366→    return all.filter(r => r.content.toLowerCase().includes(q)).slice(0, limit);
367→  },
368→};
