152→export function ClipboardHistoryView() {
153→  const nav = useNavigation();
154→  const { entries, togglePin, deleteEntry } = useClipboardHistory();
155→  const [query, setQuery] = useState('');
156→  const [filterValue, setFilterValue] = useState('all');
157→  const [selectedIndex, setSelectedIndex] = useState(0);
158→  const [actionsOpen, setActionsOpen] = useState(false);
159→  const { items: hudItems, show: showHUD } = useHUD();
160→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
161→  const now = useMemo(() => new Date(), []);
162→  const dbSearchFn = useCallback((q: string) => clipboardDb.search(q), []);
163→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
164→    query,
165→    dbSearchFn,
166→    clipboardRowToEntry,
167→  );
168→
169→  const filtered = useMemo(() => {
170→    let items = ftsResults ?? entries;
171→    if (filterValue !== 'all') {
172→      items = items.filter(e => e.contentType === filterValue);
173→    }
174→    if (!ftsResults && query) {
175→      items = items.filter(
176→        e => fuzzyMatch(query, e.content) || fuzzyMatch(query, e.sourceApp),
177→      );
178→    }
179→    return items;
180→  }, [
181→    entries,
182→    query,
183→    filterValue,
184→    ftsResults,
185→  ]);
186→
187→  const pinnedItems = useMemo(() => filtered.filter(e => e.pinned), [filtered]);
188→  const recentItems = useMemo(
189→    () => filtered.filter(e => !e.pinned),
190→    [filtered],
191→  );
192→  const totalItemCount = filtered.length;
193→
194→  const flatItems = useMemo(
195→    () => [
196→      ...pinnedItems,
197→      ...recentItems,
198→    ],
199→    [
200→      pinnedItems,
201→      recentItems,
202→    ],
203→  );
204→
205→  useEffect(() => {
206→    if (selectedIndex >= totalItemCount && totalItemCount > 0) {
207→      setSelectedIndex(totalItemCount - 1);
208→    } else if (totalItemCount === 0) {
