107→function rowToEntry(row: SnippetRow): SnippetEntry {
108→  const parsed = new Date(row.created_at);
109→  const createdAt = isNaN(parsed.getTime()) ? new Date() : parsed;
110→
111→  let tags: SnippetEntry['tags'] = [];
112→  try {
113→    const raw = JSON.parse(row.tags);
114→    if (Array.isArray(raw)) {
115→      tags = raw.map((t: {
116→        text?: string;
117→        color?: string;
118→      }) => ({
119→        text: typeof t.text === 'string' ? t.text : '',
120→        color:
121→          typeof t.color === 'string' && isTagColor(t.color)
122→            ? t.color
123→            : undefined,
124→      }));
125→    }
126→  } catch {
127→    // empty
128→  }
129→
130→  return {
131→    id: row.id,
132→    name: row.name,
133→    keyword: row.keyword,
134→    content: row.content,
135→    category: isSnippetCategory(row.category) ? row.category : 'general',
136→    tags,
137→    createdAt,
138→  };
139→}
140→
141→function entryToRow(entry: SnippetEntry): SnippetRow {
142→  return {
143→    id: entry.id,
144→    name: entry.name,
145→    keyword: entry.keyword,
146→    content: entry.content,
147→    category: entry.category,
148→    tags: JSON.stringify(entry.tags),
149→    created_at: entry.createdAt.toISOString(),
150→  };
151→}
