316→export function SnippetManagerView() {
317→  const nav = useNavigation();
318→  const [entries, setEntries] = useState<SnippetEntry[]>([]);
319→  const [query, setQuery] = useState('');
320→  const [filterValue, setFilterValue] = useState('all');
321→  const [selectedIndex, setSelectedIndex] = useState(0);
322→  const [actionsOpen, setActionsOpen] = useState(false);
323→  const [subView, setSubView] = useState<SnippetSubView>('list');
324→  const [editingSnippet, setEditingSnippet] = useState<
325→    SnippetEntry | undefined
326→  >();
327→  const { items: hudItems, show: showHUD } = useHUD();
328→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
329→  const now = useMemo(() => new Date(), []);
330→
331→  useEffect(() => {
332→    let aborted = false;
333→
334→    snippetDb
335→      .getAll()
336→      .then(rows => {
337→        if (aborted) return;
338→        if (rows.length > 0) {
339→          setEntries(rows.map(rowToEntry));
340→        } else if (!isTauri) {
341→          const mock = MOCK_SNIPPET_ENTRIES.map(e => ({ ...e }));
342→          setEntries(mock);
343→          Promise.all(mock.map(e => snippetDb.insert(entryToRow(e)))).catch(
344→            console.error,
345→          );
346→        }
347→      })
348→      .catch(err => {
349→        console.error('Failed to load snippets:', err);
350→        if (!isTauri && !aborted) {
351→          setEntries(MOCK_SNIPPET_ENTRIES.map(e => ({ ...e })));
352→        }
353→      });
354→
355→    return () => {
356→      aborted = true;
357→    };
358→  }, []);
359→
360→  const dbSearchFn = useCallback((q: string) => snippetDb.search(q), []);
361→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
362→    query,
363→    dbSearchFn,
364→    rowToEntry,
365→  );
366→
367→  const filtered = useMemo(() => {
368→    let items = ftsResults ?? entries;
369→    if (filterValue !== 'all') {
370→      items = items.filter(e => e.category === filterValue);
371→    }
372→    if (!ftsResults && query) {
373→      items = items.filter(
374→        e =>
375→          fuzzyMatch(query, e.name) ||
376→          fuzzyMatch(query, e.keyword) ||
377→          fuzzyMatch(query, e.content),
378→      );
379→    }
380→    return items;
381→  }, [
